hooks.command:
python3 -c "
import json, re, sys
try:
    data = json.load(sys.stdin)
    tool_input = data.get('tool_input', {})
    file_path = tool_input.get('file_path', '') or tool_input.get('path', '')
    if 'LEARNING_LOG' not in file_path:
        sys.exit(0)
    with open(file_path) as f:
        content = f.read()
    has_date_header = bool(re.search(r'^## \d{4}-\d{2}-\d{2}', content, re.MULTILINE))
    has_studied = '- Studied:' in content
    has_completed = '- Completed:' in content
    has_insight = '- Insight:' in content
    has_next = '- Next:' in content
    if not (has_date_header and has_studied and has_completed and has_insight and has_next):
        missing = []
        if not has_date_header: missing.append('## YYYY-MM-DD header')
        if not has_studied: missing.append('- Studied:')
        if not has_completed: missing.append('- Completed:')
        if not has_insight: missing.append('- Insight:')
        if not has_next: missing.append('- Next:')
        result = {'decision': 'block', 'reason': f'LEARNING_LOG.md entry missing required fields: {", ".join(missing)}'}
        print(json.dumps(result))
except Exception as e:
    sys.exit(0)
"
